<script>import{onMount}from'svelte';import{GitBranch,FileCode,Package,Route}from'lucide-svelte';let info=$state(null),error=$state('');onMount(async()=>{const r=await fetch('/api/repository');const d=await r.json();if(r.ok)info=d;else error=d.error})</script>
<svelte:head><title>Repository · J.A.R.V.I.S.</title></svelte:head><div class="page"><header><GitBranch size={21}/><div><h1>Repository Intelligence</h1><p>Live facts derived from the current workspace.</p></div></header>{#if error}<p>{error}</p>{:else if !info}<p>Scanning repository…</p>{:else}<section class="stats"><article><FileCode/><strong>{info.fileCount}</strong><span>tracked files</span></article><article><Route/><strong>{info.routes.length}</strong><span>route modules</span></article><article><Package/><strong>{info.dependencies.length}</strong><span>dependencies</span></article></section><section class="panels"><article><h2>Source composition</h2>{#each Object.entries(info.byExtension).sort((a,b)=>b[1]-a[1]) as entry(entry[0])}<div><code>{entry[0]}</code><span>{entry[1]}</span></div>{/each}</article><article><h2>Available commands</h2>{#each Object.entries(info.scripts) as script(script[0])}<div><code>npm run {script[0]}</code><span>{script[1]}</span></div>{/each}</article></section><section class="routes"><h2>Routes</h2>{#each info.routes as route(route)}<code>{route}</code>{/each}</section>{/if}</div>
<style>.page{padding:var(--space-6);display:grid;gap:var(--space-5)}header{display:flex;align-items:center;gap:.8rem}h1{margin:0;font-size:var(--text-2xl)}header p{margin:.25rem 0;color:var(--text-secondary);font-size:var(--text-sm)}.stats{display:grid;grid-template-columns:repeat(3,1fr);gap:.7rem}.stats article,.panels>article,.routes{border:1px solid var(--surface-border);background:var(--surface-card);border-radius:var(--radius-lg);padding:1rem}.stats article{display:grid;gap:.3rem}.stats strong{font-size:var(--text-2xl)}.stats span{font-size:var(--text-xs);color:var(--text-secondary)}.panels{display:grid;grid-template-columns:1fr 1fr;gap:.7rem}h2{font-size:var(--text-sm);margin:0 0 .7rem}.panels article div{display:flex;justify-content:space-between;border-top:1px solid var(--surface-border-subtle);padding:.45rem 0;font-size:var(--text-xs)}.routes{display:flex;flex-wrap:wrap;gap:.5rem}.routes h2{width:100%}.routes code{font-size:var(--text-xs);padding:.35rem;background:var(--surface-bg);border-radius:var(--radius-sm)}@media(max-width:700px){.page{padding:var(--space-4)}.stats,.panels{grid-template-columns:1fr}}</style>
